import React, { useState, useEffect } from 'react';

function App() {
  const [books, setBooks] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('http://localhost:5000/api/products')
      .then(res => {
        if (!res.ok) {
          throw new Error('Network response was not ok');
        }
        return res.json();
      })
      .then(data => setBooks(data))
      .catch(err => {
        console.error(err);
        setError('Failed to load books from server');
      });
  }, []);

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial, sans-serif', backgroundColor: '#f4f7f6', minHeight: '100vh' }}>
      <h1 style={{ textAlign: 'center', color: '#333', marginBottom: '30px' }}>Bookstore Platform</h1>
      
      {error && <div style={{ color: 'red', textAlign: 'center', marginBottom: '20px' }}>{error}</div>}
      
      <div style={{ display: 'flex', gap: '20px', justifyContent: 'center', flexWrap: 'wrap' }}>
        {books.map(book => (
          <div key={book.id} style={{ backgroundColor: '#fff', padding: '20px', borderRadius: '8px', boxShadow: '0 4px 8px rgba(0,0,0,0.1)', width: '250px' }}>
            <h3 style={{ margin: '0 0 10px 0', color: '#007bff' }}>{book.title}</h3>
            <p style={{ margin: '5px 0', color: '#555' }}><strong>Author:</strong> {book.author}</p>
            <p style={{ margin: '5px 0', color: '#777' }}><strong>Category:</strong> {book.category}</p>
            <p style={{ margin: '15px 0 0 0', fontWeight: 'bold', color: '#28a745', fontSize: '18px' }}>${book.price}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
